using UnityEngine;
using Climbing;
using UnityEditor;
using System.Linq;

public class ForcePhysicsFix
{
    public static string Run()
    {
        GameObject root = GameObject.Find("Player_New");
        if (root == null) root = GameObject.Find("Player");
        if (root == null) return "Player not found in scene.";

        GameObject pm = null;
        Transform pmT = root.transform.Find("PlayerModel");
        if (pmT != null) pm = pmT.gameObject;
        else pm = root;

        string report = $"--- Forcing Physics on {root.name} / {pm.name} ---\n";

        Animator anim = pm.GetComponent<Animator>();
        if (anim != null) {
            anim.applyRootMotion = false;
            report += "- Animator: Disabled ApplyRootMotion\n";
        }

        Rigidbody rb = pm.GetComponent<Rigidbody>();
        if (rb != null) {
            rb.isKinematic = false;
            rb.useGravity = true;
            rb.constraints = RigidbodyConstraints.FreezeRotation;
            report += "- Rigidbody: isKinematic=False, useGravity=True, FreezeRotation\n";
        }

        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();
        if (col != null) {
            col.isTrigger = false;
            // Typical humanoid dimensions
            col.center = new Vector3(0, 0.9f, 0);
            col.height = 1.8f;
            col.radius = 0.3f;
            report += $"- CapsuleCollider: isTrigger=False, Reset Center/Height/Radius\n";
        }

        // Check for extra colliders that might be pushing it up
        Collider[] allCols = pm.GetComponents<Collider>();
        if (allCols.Length > 1) {
            report += $"- WARNING: Found {allCols.Length} colliders on PlayerModel!\n";
        }

        // Teleport slightly above ground to let gravity do the rest
        RaycastHit hit;
        if (Physics.Raycast(root.transform.position + Vector3.up * 2f, Vector3.down, out hit, 100f)) {
            root.transform.position = hit.point + Vector3.up * 0.5f;
            report += $"- Teleported root slightly above ground at {hit.point.y}\n";
        }

        EditorUtility.SetDirty(root);
        if (pm != root) EditorUtility.SetDirty(pm);

        return report;
    }
}
